import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"黃金追蹤日誌 — 2026-06-17（TST 05:00）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-17.md","filePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-17.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-17.md"};function d(n,a,h,l,s,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="黃金追蹤日誌-—-2026-06-17-tst-05-00" tabindex="-1">黃金追蹤日誌 — 2026-06-17（TST 05:00） <a class="header-anchor" href="#黃金追蹤日誌-—-2026-06-17-tst-05-00" aria-label="Permalink to &quot;黃金追蹤日誌 — 2026-06-17（TST 05:00）&quot;">​</a></h1><h2 id="本日敘事錨點" tabindex="-1">本日敘事錨點 <a class="header-anchor" href="#本日敘事錨點" aria-label="Permalink to &quot;本日敘事錨點&quot;">​</a></h2><p><strong>核心事件：MOU 簽署後，黃金邏輯從「避險」切換至「利率+匯率雙重支撐」。</strong></p><p>今天的黃金走勢延續昨日的「反直覺」格局：股市在歷史高點、油價暴跌、risk-on 情緒升溫——照理說黃金應該跌。但它沒有。</p><p>原因在於市場已經完成邏輯切換：</p><ol><li><strong>油價下跌 → 通膨預期降溫 → 升息預期降溫</strong> → 持有黃金的機會成本下降</li><li><strong>美元跌至 96 區間</strong> → 以美元計價的黃金更便宜</li><li><strong>MOU 細節未公開</strong> → 地緣保鑣價值尚未完全退場</li></ol><p>簡單說，黃金今天的利多不是「世界更危險」，而是「利率環境對黃金更有利」。</p><p>查詢時間：2026-06-17 05:00 TST（UTC+8）。</p><hr><h2 id="_10-項追蹤指標檢查" tabindex="-1">10 項追蹤指標檢查 <a class="header-anchor" href="#_10-項追蹤指標檢查" aria-label="Permalink to &quot;10 項追蹤指標檢查&quot;">​</a></h2><h3 id="_1-comex-黃金現貨價格" tabindex="-1">1. COMEX 黃金現貨價格 <a class="header-anchor" href="#_1-comex-黃金現貨價格" aria-label="Permalink to &quot;1. COMEX 黃金現貨價格&quot;">​</a></h3><p>現貨黃金約 <strong>4,334 美元/盎司</strong>（+0.57%），連續兩日走強。<br> 自歷史高點 5,608 美元（2026年1月）回落約 22.7%，但近一個月下跌 5.09%，一年仍漲 27.95%。<br> 來源：TradingEconomics (2026-06-16)、Kitco (2026-06-16)</p><h3 id="_2-美國-10-年期-tips-實質利率" tabindex="-1">2. 美國 10 年期 TIPS 實質利率 <a class="header-anchor" href="#_2-美國-10-年期-tips-實質利率" aria-label="Permalink to &quot;2. 美國 10 年期 TIPS 實質利率&quot;">​</a></h3><p>本日未取得最新即時讀數。但從「公債殖利率下滑 + 黃金走強」的組合來看，實質利率壓力暫時減弱。美國 10 年期公債殖利率約 4.455%（-0.04%）。<br> 來源：WSJ Market Data (2026-06-16)、TradingEconomics (2026-06-16)</p><h3 id="_3-美元指數-dxy" tabindex="-1">3. 美元指數 DXY <a class="header-anchor" href="#_3-美元指數-dxy" aria-label="Permalink to &quot;3. 美元指數 DXY&quot;">​</a></h3><p>美元回落至約 <strong>96.14–96.19</strong> 區間，較昨日再跌 0.05-0.10%。美元走弱對黃金形成直接支撐。<br> 來源：WSJ Market Data (2026-06-16)、TradingEconomics (2026-06-16)</p><h3 id="_4-聯準會利率決策-點陣圖" tabindex="-1">4. 聯準會利率決策 + 點陣圖 <a class="header-anchor" href="#_4-聯準會利率決策-點陣圖" aria-label="Permalink to &quot;4. 聯準會利率決策 + 點陣圖&quot;">​</a></h3><p>市場普遍預期本週 FOMC 維持 3.50-3.75% 不變。<br> 但 CME FedWatch 顯示：交易員已定價 12 月有 <strong>42% 機率升息 25bp</strong>，降息要到 2027 年中。<br> Warsh 首次主持的政策語氣將決定黃金後續走向。<br> 來源：Reuters (2026-06-16)、Kitco (2026-06-16)</p><h3 id="_5-央行購金數據-wgc-季報" tabindex="-1">5. 央行購金數據（WGC 季報） <a class="header-anchor" href="#_5-央行購金數據-wgc-季報" aria-label="Permalink to &quot;5. 央行購金數據（WGC 季報）&quot;">​</a></h3><p>本日無新官方數據。但近期媒體仍持續提及央行購金結構是支撐中長期金價的重要因素。今日僅標記「結構性支撐仍在」。<br> 來源：Kitco (2026-06-16)</p><h3 id="_6-地緣風險事件" tabindex="-1">6. 地緣風險事件 <a class="header-anchor" href="#_6-地緣風險事件" aria-label="Permalink to &quot;6. 地緣風險事件&quot;">​</a></h3><p>MOU 已提前簽署，CENTCOM 封鎖解除。但文本未公開、雙方解讀分歧（伊朗稱60天後可恢復通行費），黃金的「地緣保鑣價值」尚未完全退場。<br> 來源：Maritime Executive (2026-06-15)、Reuters (2026-06-14)</p><h3 id="_7-通膨數據-cpi、pce" tabindex="-1">7. 通膨數據（CPI、PCE） <a class="header-anchor" href="#_7-通膨數據-cpi、pce" aria-label="Permalink to &quot;7. 通膨數據（CPI、PCE）&quot;">​</a></h3><p>美國通膨率約 4.2%（5月CPI），仍高于 Fed 2% 目標。油價下跌可能壓縮未來通膨壓力，但目前水準仍偏高。<br> 來源：TradingEconomics (2026-06-16)</p><h3 id="_8-黃金-etf-持倉量" tabindex="-1">8. 黃金 ETF 持倉量 <a class="header-anchor" href="#_8-黃金-etf-持倉量" aria-label="Permalink to &quot;8. 黃金 ETF 持倉量&quot;">​</a></h3><p>今日未取得即時 ETF 持倉更新。目前先以價格與宏觀面判斷為主。<br> 查詢時間：2026-06-17 05:00 TST。</p><h3 id="_9-黃金礦產供應" tabindex="-1">9. 黃金礦產供應 <a class="header-anchor" href="#_9-黃金礦產供應" aria-label="Permalink to &quot;9. 黃金礦產供應&quot;">​</a></h3><p>今日無重大新聞。供給端不是本日驅動因子。<br> 查詢時間：2026-06-17 05:00 TST。</p><h3 id="_10-大型投行金價預測" tabindex="-1">10. 大型投行金價預測 <a class="header-anchor" href="#_10-大型投行金價預測" aria-label="Permalink to &quot;10. 大型投行金價預測&quot;">​</a></h3><p>花旗上調短期金價預測至 <strong>4,500 美元</strong>，維持中期 <strong>5,000 美元</strong> 看法。TradingEconomics 模型預估本季底 4,239 美元、12個月後 4,597 美元。<br> 來源：TradingEconomics (2026-06-16)、Kitco (2026-06-15)</p><hr><h2 id="有什麼變化" tabindex="-1">有什麼變化？ <a class="header-anchor" href="#有什麼變化" aria-label="Permalink to &quot;有什麼變化？&quot;">​</a></h2><h3 id="變化一-黃金在-risk-on-環境下仍漲-邏輯已切換" tabindex="-1">變化一：黃金在 risk-on 環境下仍漲，邏輯已切換 <a class="header-anchor" href="#變化一-黃金在-risk-on-環境下仍漲-邏輯已切換" aria-label="Permalink to &quot;變化一：黃金在 risk-on 環境下仍漲，邏輯已切換&quot;">​</a></h3><p>變化內容：股市歷史高、油價暴跌，但黃金仍漲 0.57%。<br> 為什麼：油價下跌 → 通膨預期降溫 → 升息預期降溫 → 持有黃金機會成本下降。<br> 影響：黃金從「單一避險資產」正式切換成「利率+匯率+地緣混合資產」。<br> 關鍵節點：本週 FOMC 語氣。<br> 來源：TradingEconomics (2026-06-16)、Kitco (2026-06-16)</p><h3 id="變化二-美元跌至-96-區間-黃金獲得匯率支撐" tabindex="-1">變化二：美元跌至 96 區間，黃金獲得匯率支撐 <a class="header-anchor" href="#變化二-美元跌至-96-區間-黃金獲得匯率支撐" aria-label="Permalink to &quot;變化二：美元跌至 96 區間，黃金獲得匯率支撐&quot;">​</a></h3><p>變化內容：DXY 跌至 96.14，為近期低檔。<br> 為什麼：避險退潮 + 荷莫茲復航預期壓低美元。<br> 影響：以美元計價的黃金更便宜，國際買盤更容易進場。<br> 關鍵節點：Fed 記者會的政策語氣。<br> 來源：WSJ Market Data (2026-06-16)</p><hr><h2 id="投行預測彙整" tabindex="-1">投行預測彙整 <a class="header-anchor" href="#投行預測彙整" aria-label="Permalink to &quot;投行預測彙整&quot;">​</a></h2><table tabindex="0"><thead><tr><th>投行/來源</th><th>短期展望</th><th>中期展望</th><th>今日判斷</th></tr></thead><tbody><tr><td>TradingEconomics 模型</td><td>本季底 4,239</td><td>12個月 4,597</td><td>偏多震盪</td></tr><tr><td>Citi</td><td>上調至 4,500</td><td>維持 5,000</td><td>偏多</td></tr><tr><td>UBS</td><td>短線可能整理</td><td>等待本週 Fed</td><td>中性偏多</td></tr><tr><td>Barclays</td><td>仍看好</td><td>中期支撐仍在</td><td>偏多</td></tr></tbody></table><hr><h2 id="延續昨日敘事" tabindex="-1">延續昨日敘事 <a class="header-anchor" href="#延續昨日敘事" aria-label="Permalink to &quot;延續昨日敘事&quot;">​</a></h2><p>昨日報告指出：黃金不是因為「世界更危險」而漲，而是因為「利率與通膨預期變得更有利」而漲。</p><p>今天已驗證：MOU 簽署後，黃金仍維持偏強，代表市場已接受「油價下跌 → 利率環境改善」的邏輯鏈。</p><p>短期觀察重點：</p><ol><li>本週 FOMC Warsh 記者會的政策語氣</li><li>美元是否續弱（96 區間能否守住）</li><li>通膨數據（油價下跌是否真的壓縮通膨預期）</li></ol><p>查詢時間：2026-06-17 05:00 TST。</p>',46)])])}const _=t(i,[["render",d]]);export{p as __pageData,_ as default};
